import '../styles/services.css';

function Services() {
  return (
    <div className="services">
      <h1>Our Services</h1>
      <ul>
        <li>Outpatient Care</li>
        <li>Maternity</li>
        <li>Dental</li>
        <li>Pharmacy</li>
      </ul>
    </div>
  );
}

export default Services;
